# Utility module with complex features

# Enum for status codes
enum Status:
    OK = 0
    PENDING = 1
    ERROR = 2

# Generic result wrapper class
@abstract
class Container[T]:
    @abstract
    def get_value(self) -> T: ...

    @abstract
    def is_present(self) -> bool: ...

class Box[T](Container[T]):
    def __init__(self, value: T):
        self._value: T = value

    @override
    def get_value(self) -> T:
        return self._value

    @override
    def is_present(self) -> bool:
        return True

class Empty[T](Container[T]):
    @override
    def get_value(self) -> T:
        raise ValueError("No value present")

    @override
    def is_present(self) -> bool:
        return False

# Numeric operations
def factorial(n: int) -> int:
    if n < 0:
        raise ValueError("Factorial not defined for negative numbers")
    if n == 0:
        return 1
    return n * factorial(n - 1)

def fibonacci(n: int) -> int:
    if n < 0:
        return 0
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

# String utilities
def reverse_string(s: str) -> str:
    result: str = ""
    for char in s:
        result = str(char) + result
    return result

def is_palindrome(s: str) -> bool:
    return s == reverse_string(s)

# List utilities
def sum_list(nums: list[int]) -> int:
    total: int = 0
    for n in nums:
        total += n
    return total

def find_max(nums: list[int]) -> int:
    if len(nums) == 0:
        raise ValueError("Empty list")
    max_val: int = nums[0]
    for n in nums:
        if n > max_val:
            max_val = n
    return max_val

# Math utilities
def gcd(a: int, b: int) -> int:
    while b != 0:
        temp: int = b
        b = a % b
        a = temp
    return a

def lcm(a: int, b: int) -> int:
    if a == 0 or b == 0:
        return 0
    return (a * b) // gcd(a, b)
